 3→const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;
 4→
 5→export function resolveContextPath(
 6→  context: SDUIContext,
 7→  path: string,
 8→): SDUIContextValue {
 9→  const segments = path.trim().split('.');
10→  let current: SDUIContextValue = context;
11→
12→  for (const segment of segments) {
13→    if (current === null || current === undefined) return '';
14→    if (typeof current !== 'object' || Array.isArray(current)) return '';
15→    current = (current as SDUIContext)[segment];
16→  }
17→
18→  return current ?? '';
19→}
20→
21→export function interpolateString(
22→  template: string,
23→  context: SDUIContext,
24→): string {
25→  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
26→    const value = resolveContextPath(context, path);
27→    if (value === null || value === undefined) return '';
28→    if (typeof value === 'object') return '';
29→    return String(value);
30→  });
31→}
32→
33→export function interpolateDeep<T>(value: T, context: SDUIContext): T {
34→  if (typeof value === 'string') {
35→    return interpolateString(value, context) as T;
36→  }
37→
38→  if (Array.isArray(value)) {
39→    return value.map(item => interpolateDeep(item, context)) as T;
40→  }
41→
42→  if (value !== null && typeof value === 'object') {
43→    const result: Record<string, unknown> = {};
44→    for (const key of Object.keys(value)) {
45→      result[key] = interpolateDeep(
46→        (value as Record<string, unknown>)[key],
47→        context,
48→      );
49→    }
50→    return result as T;
51→  }
52→
53→  return value;
54→}
